import { TZDateMini } from '@date-fns/tz';
import {
  differenceInMilliseconds,
  differenceInCalendarMonths,
  differenceInCalendarYears,
  differenceInCalendarDays,
  differenceInHours,
  differenceInMinutes,
  differenceInSeconds,
  differenceInCalendarWeeks,
  differenceInCalendarQuarters,
} from 'date-fns';

import {
  _getDateFromExpression,
  _parseTimeExpression,
} from '@dynatrace-sdk/units';
import { getTimezone } from '@dynatrace-sdk/user-preferences';

import type { TimeValue } from '../../../core/types/time.js';

/**
 * Contains details for an expression, including offset and round-down units.
 */
type ExpressionDetails = {
  offsetAmount: number;
  offsetUnit?: OffsetUnit;
  roundDownUnit?: RoundDownUnit;
};

/**
 * Defines the units of time that can be used for offsetting.
 */
type OffsetUnit = 'y' | 'q' | 'M' | 'w' | 'd' | 'h' | 'm' | 's' | 'ms';

/**
 * Defines the units of time that can be used for rounding down.
 */
type RoundDownUnit =
  | 'y'
  | 'q'
  | 'M'
  | 'w'
  | 'w0'
  | 'w1'
  | 'w2'
  | 'w3'
  | 'w4'
  | 'w5'
  | 'w6'
  | 'd'
  | 'h'
  | 'm'
  | 's';

/** Maps time units to their respective order for comparison. */
const unitOrder: Record<OffsetUnit | RoundDownUnit, number> = {
  y: 9,
  q: 8,
  M: 7,
  w: 6,
  w0: 6,
  w1: 6,
  w2: 6,
  w3: 6,
  w4: 6,
  w5: 6,
  w6: 6,
  d: 5,
  h: 4,
  m: 3,
  s: 2,
  ms: 1,
};

/**
 * Determines the smallest common denominator for OffsetUnits.
 */
function isSmallestCommonDenominatorUnit(
  left: OffsetUnit | RoundDownUnit | undefined,
  right: OffsetUnit | RoundDownUnit | undefined,
): OffsetUnit | RoundDownUnit {
  if (left === undefined) {
    return right ?? 'ms';
  }
  if (right === undefined) {
    return left ?? 'ms';
  }
  return unitOrder[left] < unitOrder[right] ? left : right;
}

/**
 * Determines the lowest common denominator for OffsetUnits between two TimeValues.
 * @internal
 */
export function getSmallestCommonUnit(
  from: TimeValue | undefined | null,
  to: TimeValue | undefined | null,
): OffsetUnit {
  const newFrom = _parseTimeExpression(from?.value || '');
  const newTo = _parseTimeExpression(to?.value || '');
  if (newFrom && newTo) {
    const unit = isSmallestCommonDenominatorUnit(
      // Use roundDownUnit only when there is no offsetUnit, such as in '@d -> now'.
      // For cases with both roundDownUnit and offsetUnit, like '+1M@d -> +2M@d',
      // rely solely on the offsetUnit to prevent unwanted conversions like '+1d@d'.
      newFrom.offsetUnit || newTo.offsetUnit || newFrom.roundDownUnit,
      newTo.offsetUnit || newFrom.offsetUnit || newTo.roundDownUnit,
    );

    switch (unit) {
      case 'w0':
      case 'w1':
      case 'w2':
      case 'w3':
      case 'w4':
      case 'w5':
      case 'w6':
        return 'w';
      default:
        return unit;
    }
  }
  return 'ms';
}

/**
 * Returns the difference between two TimeValues in the lowest possible OffsetUnit.
 * @internal
 */
export function getDifference(
  from: TimeValue | undefined | null,
  to: TimeValue | undefined | null,
): number {
  const timezone = getTimezone();

  const relativeDate = TZDateMini.tz(timezone).getTime();
  const newFrom = _parseTimeExpression(from?.value || '');
  const newTo = _parseTimeExpression(to?.value || '');

  // expression.
  if (newFrom && newTo) {
    const lowestUnit = getSmallestCommonUnit(from, to);

    // need to calculate the offsetAmount in the correct OffsetUnit to prevent mixed Unit calculations.
    return (
      getTimeDifferenceInUnit(newFrom, relativeDate, lowestUnit) -
      getTimeDifferenceInUnit(newTo, relativeDate, lowestUnit)
    );
  }

  // iso8601.
  if (from?.absoluteDate && to?.absoluteDate) {
    return Math.abs(
      new TZDateMini(from.absoluteDate, timezone).getTime() -
        new TZDateMini(to.absoluteDate, timezone).getTime(),
    );
  }
  return 0;
}

/**
 * Calculates the difference between a relative time and now in a specified OffsetUnit.
 * @internal
 */
export function getTimeDifferenceInUnit(
  details: ExpressionDetails | undefined,
  relativeDate: number,
  targetUnit: OffsetUnit | RoundDownUnit | undefined,
): number {
  if (!details) {
    return 0;
  }

  const newDate = new TZDateMini(relativeDate, getTimezone());
  const expressionDate = _getDateFromExpression(details, relativeDate);
  if (!expressionDate) {
    return 0;
  }
  switch (targetUnit) {
    case 'ms':
      return differenceInMilliseconds(expressionDate, newDate);
    case 's':
      return differenceInSeconds(expressionDate, newDate);
    case 'm':
      return differenceInMinutes(expressionDate, newDate);
    case 'h':
      return differenceInHours(expressionDate, newDate);
    case 'd':
      return differenceInCalendarDays(expressionDate, newDate);
    case 'w':
      return differenceInCalendarWeeks(expressionDate, newDate);
    case 'M':
      return differenceInCalendarMonths(expressionDate, newDate);
    case 'q':
      return differenceInCalendarQuarters(expressionDate, newDate);
    case 'y':
      return differenceInCalendarYears(expressionDate, newDate);
    default:
      return differenceInMilliseconds(expressionDate, newDate);
  }
}
